{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is a classic textbook example of the Ritter reaction. Tert-butanol is protonated by a strong acid (sulfuric acid) and loses water to form a stable tert-butyl carbocation. This carbocation is then trapped by the nucleophilic nitrogen of acetonitrile, forming a nitrilium ion intermediate. Subsequent hydrolysis yields the final product, N-tert-butylacetamide. The reactants are simple, acyclic, and clearly demonstrate the core transformation: carbocation source + nitrile -> N-alkyl amide.",
    "collision_avoidance_note": "This example uses simple, acyclic, saturated aliphatic substrates (tert-butanol and acetonitrile) to avoid overlap with other named reactions. It avoids arenes (Friedel-Crafts), alkenes (Markovnikov addition, Prins), carbonyls (Beckmann rearrangement), or other complex functional groups that could trigger false positives for different reaction families. The core transformation is clearly the addition of a nitrile to a carbocation, which is the defining feature of the Ritter reaction."
  }
}
